class Solution:
    def kthLargestValue(self, matrix, k):
        import heapq
        m = len(matrix)
        n = len(matrix[0])
        pref = [[0] * (n + 1) for _ in range(m + 1)]
        heap = []
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                v = pref[i - 1][j] ^ pref[i][j - 1] ^ pref[i - 1][j - 1] ^ matrix[i - 1][j - 1]
                pref[i][j] = v
                if len(heap) < k:
                    heapq.heappush(heap, v)
                elif v > heap[0]:
                    heapq.heapreplace(heap, v)
        return heap[0]

