var kthLargestValue = function(matrix, k) {
    const m = matrix.length, n = matrix[0].length;
    const pref = Array.from({length: m + 1}, () => new Array(n + 1).fill(0));
    const vals = [];
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            const v = pref[i - 1][j] ^ pref[i][j - 1] ^ pref[i - 1][j - 1] ^ matrix[i - 1][j - 1];
            pref[i][j] = v;
            vals.push(v);
        }
    }
    vals.sort((a, b) => a - b);
    return vals[vals.length - k];
};
